func All() []models.Question { return append([]models.Question(nil), bank...) }

func ForGrade(grade int) []models.Question {
	if grade < 9 || grade > 11 {
		return All()
	}
	out := make([]models.Question, 0)
	for _, q := range bank {
		if q.Grade == grade {
			out = append(out, q)
		}
	}
	return out
}

func Tasks() []models.TerminalTask { return append([]models.TerminalTask(nil), tasks...) }

func TasksForGrade(grade int) []models.TerminalTask {
	out := make([]models.TerminalTask, 0)
	for _, t := range tasks {
		if t.Grade == grade || t.Grade == 0 {
			out = append(out, t)
		}
	}
	return out
}
